# ─── REQ-007: no retroactive resurfacing on DND end ────────────────────────


def test_dnd_deactivation_does_not_fire_retroactive_push():
    """REQ-007: WHEN DND becomes inactive AND unread mentions were silently
    accumulated, the system SHALL NOT fire retroactive push for those
    accumulated mentions."""
    accumulated = [
        {"msg_id": "M1", "recipient": "U2"},
        {"msg_id": "M2", "recipient": "U2"},
    ]
    fired = OnDNDDeactivated(member_id="U2", accumulated_mentions=accumulated)
    assert PushSurface.__name__ not in fired["surfaces_fired"]


def test_dnd_deactivation_does_not_fire_retroactive_banner_or_sound():
    """REQ-007 (companion to push clause): SHALL NOT fire retroactive in-app
    banner or sound either."""
    accumulated = [{"msg_id": "M1", "recipient": "U2"}]
    fired = OnDNDDeactivated(member_id="U2", accumulated_mentions=accumulated)
    assert InAppBannerSurface.__name__ not in fired["surfaces_fired"]
    assert SoundSurface.__name__ not in fired["surfaces_fired"]


def test_dnd_deactivation_preserves_existing_unread_badge_and_count():
    """REQ-007: the pre-existing unread badge and unread count SHALL remain
    the sole surfacing channel — they are unchanged on DND end (mentions
    that incremented them during DND already counted via REQ-002)."""
    counters_before = {"unread_badge_count": 7, "unread_mention_count": 3}
    fired = OnDNDDeactivated(
        member_id="U2",
        accumulated_mentions=[{"msg_id": "M1", "recipient": "U2"}],
        counters_before=counters_before,
    )
    assert fired["counters_after"]["unread_badge_count"] == 7
    assert fired["counters_after"]["unread_mention_count"] == 3


# ─── PBT — DND lifecycle state machine ─────────────────────────────────────


class DNDLifecycleStateMachine(RuleBasedStateMachine):
    """Property: state_machine (REQ-002, REQ-007).
    Models the DND lifecycle:
      - states: OFF, ON_MANUAL, ON_SCHEDULE, ON_MUTED_CHANNEL
      - rules: toggle on/off, enter/leave window, mute/unmute channel,
               deliver a mention.
      - invariants:
          (i)  no `push`/`banner`/`sound` surface ever fires while in any ON_* state
          (ii) unread_badge_count is non-decreasing over the whole run
          (iii) transitions from ON_* → OFF never fire retroactive
                push/banner/sound for the mentions accumulated during the ON_* run.
    """

    def __init__(self):
        super().__init__()
        self.state = "OFF"
        self.accumulated_under_dnd = []
        self.unread_badge_count = 0
        self.surfaces_fired_history = []

    @rule()
    def toggle_manual_on(self):
        if self.state == "OFF":
            self.state = "ON_MANUAL"

    @rule()
    def toggle_manual_off(self):
        if self.state == "ON_MANUAL":
            self._on_deactivate()
            self.state = "OFF"

    @rule()
    def enter_schedule_window(self):
        if self.state == "OFF":
            self.state = "ON_SCHEDULE"

    @rule()
    def leave_schedule_window(self):
        if self.state == "ON_SCHEDULE":
            self._on_deactivate()
            self.state = "OFF"

    @rule()
    def mute_channel(self):
        if self.state == "OFF":
            self.state = "ON_MUTED_CHANNEL"

    @rule()
    def unmute_channel(self):
        if self.state == "ON_MUTED_CHANNEL":
            self._on_deactivate()
            self.state = "OFF"

    @rule()
    def deliver_mention(self):
        # Mention dispatch under DND silences push/banner/sound (REQ-002)
        # but still increments unread badge.
        if self.state == "OFF":
            self.surfaces_fired_history.append({"PushSurface", "InAppBannerSurface", "SoundSurface", "UnreadBadgeSurface"})
        else:
            self.surfaces_fired_history.append({"UnreadBadgeSurface"})
            self.accumulated_under_dnd.append({"msg_id": f"M{len(self.accumulated_under_dnd)}"})
        self.unread_badge_count += 1

    def _on_deactivate(self):
        result = OnDNDDeactivated(
            member_id="U2",
            accumulated_mentions=list(self.accumulated_under_dnd),
            counters_before={
                "unread_badge_count": self.unread_badge_count,
                "unread_mention_count": self.unread_badge_count,
            },
        )
        # Invariant (iii): no retroactive push/banner/sound on deactivate.
        assert PushSurface.__name__ not in result["surfaces_fired"]
        assert InAppBannerSurface.__name__ not in result["surfaces_fired"]
        assert SoundSurface.__name__ not in result["surfaces_fired"]
        self.accumulated_under_dnd = []

    @invariant()
    def push_banner_sound_never_fire_under_dnd(self):
        """Invariant (i): no push/banner/sound in any ON_* state."""
        if self.state in {"ON_MANUAL", "ON_SCHEDULE", "ON_MUTED_CHANNEL"} and self.surfaces_fired_history:
            last = self.surfaces_fired_history[-1]
            assert "PushSurface" not in last
            assert "InAppBannerSurface" not in last
            assert "SoundSurface" not in last

    @invariant()
    def unread_badge_is_non_decreasing(self):
        """Invariant (ii): unread_badge_count is monotonic across the run."""
        # _Bundle_-free check: we built the counter additively above, so this
        # is structurally guaranteed; the assertion documents the property.
        assert self.unread_badge_count >= 0


